// stack_trace
try {
  doSomething();
} catch (e) {
  console.error('stack trace:\n' + e.stack);
}

import traceback
try:
    do_something()
except Exception as e:
    traceback.print_exc()

CREATE TABLE error_log (
    error_id INT PRIMARY KEY,
    stack_trace TEXT
);
INSERT INTO error_log VALUES (1, 'Exception at line 42');
